namespace sv_9c1413a9927442d9bdd480e33adaa49b.Client.Models;

public sealed record Shipment(
    string TrackingNumber,
    string Status,
    string Location,
    DateTimeOffset EstimatedDelivery,
    IReadOnlyList<StatusUpdate> StatusUpdates);

public sealed record StatusUpdate(
    string Description,
    string Location,
    DateTimeOffset Timestamp);

using sv_9c1413a9927442d9bdd480e33adaa49b.Client.Models;

namespace sv_9c1413a9927442d9bdd480e33adaa49b.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_9c1413a9927442d9bdd480e33adaa49b.Client.Models;

namespace sv_9c1413a9927442d9bdd480e33adaa49b.Client.Services;

/// <summary>
/// Client-side implementation that calls the server API over HTTP.
/// Used when the component is running in WebAssembly.
/// </summary>
public sealed class HttpShipmentService(HttpClient httpClient) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await httpClient.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

using sv_9c1413a9927442d9bdd480e33adaa49b.Client.Models;
using sv_9c1413a9927442d9bdd480e33adaa49b.Client.Services;

namespace sv_9c1413a9927442d9bdd480e33adaa49b.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded fake data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> SeedData = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-001"] = new Shipment(
            TrackingNumber: "TRK-001",
            Status: "In Transit",
            Location: "Chicago, IL",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 25, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates: [
                new StatusUpdate("Package picked up", "New York, NY", new DateTimeOffset(2026, 5, 20, 9, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("Departed facility", "New York, NY", new DateTimeOffset(2026, 5, 20, 14, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("Arrived at sorting center", "Chicago, IL", new DateTimeOffset(2026, 5, 21, 6, 45, 0, TimeSpan.Zero)),
                new StatusUpdate("In transit to destination", "Chicago, IL", new DateTimeOffset(2026, 5, 22, 8, 0, 0, TimeSpan.Zero)),
            ]),

        ["TRK-002"] = new Shipment(
            TrackingNumber: "TRK-002",
            Status: "Delivered",
            Location: "San Francisco, CA",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates: [
                new StatusUpdate("Package picked up", "Seattle, WA", new DateTimeOffset(2026, 5, 18, 10, 0, 0, TimeSpan.Zero)),
                new StatusUpdate("In transit", "Portland, OR", new DateTimeOffset(2026, 5, 19, 7, 15, 0, TimeSpan.Zero)),
                new StatusUpdate("Out for delivery", "San Francisco, CA", new DateTimeOffset(2026, 5, 21, 8, 30, 0, TimeSpan.Zero)),
                new StatusUpdate("Delivered", "San Francisco, CA", new DateTimeOffset(2026, 5, 21, 11, 42, 0, TimeSpan.Zero)),
            ]),

        ["TRK-003"] = new Shipment(
            TrackingNumber: "TRK-003",
            Status: "Processing",
            Location: "Dallas, TX",
            EstimatedDelivery: new DateTimeOffset(2026, 5, 28, 15, 0, 0, TimeSpan.Zero),
            StatusUpdates: [
                new StatusUpdate("Label created", "Dallas, TX", new DateTimeOffset(2026, 5, 22, 14, 0, 0, TimeSpan.Zero)),
            ]),
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        // Simulate slow backend
        await Task.Delay(1500, ct);

        SeedData.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

